// Solution
function findDuplicateIndices(arr) {
  let frequencyMap = new Map();
  let result = [];
  for (let i = 0; i < arr.length; i++) {
    let frequency = frequencyMap.get(arr[i]) || 0;
    frequencyMap.set(arr[i], frequency + 1);
    if (frequency + 1 > 2) {
      result.push(i);
    }
  }
  return result;
}
